import React, { useRef, useEffect, useState } from 'react';

import { Document, Page } from 'react-pdf';
import 'react-pdf/dist/Page/TextLayer.css';
import { 
  Box, 
  Typography, 
  Paper, 
  CircularProgress, 
  Alert, 
  AlertTitle,
  Grid,
  List, 
  ListItem, 
  ListItemIcon,
  ListItemText,
  IconButton,
  Tooltip,
  useTheme,
  Button,
  Chip
} from '@mui/material';
import { 
  ExpandMore as ExpandMoreIcon,
  Info as InfoIcon,
  Error as ErrorIcon,
  ContentCopy as ContentCopyIcon,
  OpenInNew as OpenInNewIcon,
  Article as ArticleIcon,
  CheckCircle as CheckCircleIcon,
  Warning as WarningIcon
} from '@mui/icons-material';

const AnalysisResults = ({ results, loading, error, policySource }) => {
  const theme = useTheme();
  const [numPages, setNumPages] = useState(null);
  const [pageNumber, setPageNumber] = useState(1);
  const [pdfUrl, setPdfUrl] = useState(null);
  const pdfViewerRef = useRef(null);

  const handleCopyToClipboard = (text) => {
    navigator.clipboard.writeText(text);
  };

  const onDocumentLoadSuccess = ({ numPages }) => {
    setNumPages(numPages);
  };

  useEffect(() => {
    if (policySource?.type === 'file' && policySource.content) {
      const fileUrl = URL.createObjectURL(policySource.content);
      setPdfUrl(fileUrl);
      return () => URL.revokeObjectURL(fileUrl);
    } else if (policySource?.type === 'url' && policySource.content) {
      setPdfUrl(policySource.content);
    }
  }, [policySource]);

  const handleClauseClick = (clause, event) => {
    event.preventDefault();
    
    if (!policySource) return;

    if (policySource.type === 'file' && pdfViewerRef.current) {
      console.log('Scroll PDF to clause:', clause);
      return;
    }
    
    if (policySource.type === 'url' && policySource.content) {
      const sectionId = (clause.section || '')
        .toLowerCase()
        .replace(/[^a-z0-9\s-]/g, '')
        .replace(/\s+/g, '-')
        .replace(/--+/g, '-');
      
      window.open(`${policySource.content}#${sectionId}`, '_blank');
    }
  };

  const renderClauses = (clauses) => {
    if (!clauses || !Array.isArray(clauses)) return null;
    
    return (
      <List>
        {clauses.map((clause, index) => (
          <ListItem key={index}>
            <ListItemText primary={clause} />
          </ListItem>
        ))}
      </List>
    );
  };

  if (loading) {
    return (
      <Box sx={{ 
        display: 'flex', 
        flexDirection: 'column', 
        alignItems: 'center', 
        justifyContent: 'center', 
        minHeight: 300,
        py: 8
      }}>
        <CircularProgress size={60} thickness={4} sx={{ mb: 3, color: 'primary.main' }} />
        <Typography variant="h6" color="text.secondary">
          Analyzing your privacy policy...
        </Typography>
        <Typography variant="body2" color="text.secondary" sx={{ mt: 1 }}>
          This may take a few moments
        </Typography>
      </Box>
    );
  }

  if (error) {
    return (
      <Alert 
        severity="error" 
        sx={{ 
          mb: 4, 
          '& .MuiAlert-message': {
            width: '100%'
          }
        }}
      >
        <AlertTitle>Analysis Failed</AlertTitle>
        {error}
      </Alert>
    );
  }

  if (!results) {
    return null;
  }

  return (
    <Box sx={{ width: '100%' }}>
      {/* Header Section */}
      <Box sx={{ mb: 6, textAlign: 'center' }}>
        <Typography 
          variant="h4" 
          component="h2" 
          gutterBottom 
          sx={{ 
            fontWeight: 700, 
            mb: 2,
            background: 'linear-gradient(90deg, #3f51b5 0%, #2196f3 100%)',
            WebkitBackgroundClip: 'text',
            WebkitTextFillColor: 'transparent',
            display: 'inline-block'
          }}
        >
          Analysis Results
        </Typography>
        <Typography variant="body1" color="text.secondary" sx={{ maxWidth: 700, mx: 'auto' }}>
          Here's our analysis of the privacy policy you provided
        </Typography>
      </Box>

      {/* Summary Section */}
      {results.summary && (
        <Paper 
          elevation={0} 
          sx={{ 
            p: 4, 
            mb: 4, 
            borderRadius: 3,
            border: '1px solid',
            borderColor: 'divider',
            bgcolor: 'background.paper'
          }}
        >
          <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
            <InfoIcon color="primary" sx={{ mr: 1.5, fontSize: 28 }} />
            <Typography variant="h6" component="h3" sx={{ fontWeight: 600 }}>
              Policy Summary
            </Typography>
          </Box>
          <Typography variant="body1" sx={{ color: 'text.secondary', lineHeight: 1.8 }}>
            {results.summary}
          </Typography>
        </Paper>
      )}

      <Grid container spacing={4}>
        {/* Key Points */}
        {results.keyPoints && results.keyPoints.length > 0 && (
          <Grid item xs={12} md={6}>
            <Paper 
              elevation={0} 
              sx={{ 
                height: '100%', 
                p: 4, 
                borderRadius: 3,
                border: '1px solid',
                borderColor: 'divider',
                bgcolor: 'background.paper'
              }}
            >
              <Box sx={{ display: 'flex', alignItems: 'center', mb: 3 }}>
                <CheckCircleIcon color="success" sx={{ mr: 1.5, fontSize: 28 }} />
                <Typography variant="h6" component="h3" sx={{ fontWeight: 600 }}>
                  Key Points
                </Typography>
              </Box>
              <List disablePadding>
                {results.keyPoints.map((point, index) => (
                  <ListItem key={index} disableGutters sx={{ py: 0.75, px: 0 }}>
                    <ListItemIcon sx={{ minWidth: 36 }}>
                      <CheckCircleIcon color="success" fontSize="small" />
                    </ListItemIcon>
                    <ListItemText 
                      primary={
                        <Typography variant="body1" color="text.primary">
                          {point}
                        </Typography>
                      } 
                    />
                  </ListItem>
                ))}
              </List>
            </Paper>
          </Grid>
        )}

        {/* Concerns */}
        {results.concerns && results.concerns.length > 0 && (
          <Grid item xs={12} md={6}>
            <Paper 
              elevation={0} 
              sx={{ 
                height: '100%', 
                p: 4, 
                borderRadius: 3,
                border: '1px solid',
                borderColor: 'divider',
                bgcolor: 'background.paper'
              }}
            >
              <Box sx={{ display: 'flex', alignItems: 'center', mb: 3 }}>
                <WarningIcon color="warning" sx={{ mr: 1.5, fontSize: 28 }} />
                <Typography variant="h6" component="h3" sx={{ fontWeight: 600 }}>
                  Potential Concerns
                </Typography>
              </Box>
              <List disablePadding>
                {results.concerns.map((concern, index) => (
                  <ListItem key={`concern-${index}`} disableGutters sx={{ py: 0.75, px: 0 }}>
                    <ListItemIcon sx={{ minWidth: 36 }}>
                      <ErrorIcon color="error" fontSize="small" />
                    </ListItemIcon>
                    <ListItemText 
                      primary={
                        <Typography variant="body1" color="text.primary">
                          {concern}
                        </Typography>
                      } 
                    />
                  </ListItem>
                ))}
              </List>
            </Paper>
          </Grid>
        )}
      </Grid>

      {/* Related Clauses */}
      {results.relatedClauses && results.relatedClauses.length > 0 && (
        <Paper 
          elevation={0} 
          sx={{ 
            mt: 4, 
            p: 4, 
            borderRadius: 3,
            border: '1px solid',
            borderColor: 'divider',
            bgcolor: 'background.paper'
          }}
        >
          <Box sx={{ display: 'flex', alignItems: 'center', mb: 3 }}>
            <ArticleIcon color="info" sx={{ mr: 1.5, fontSize: 28 }} />
            <Typography variant="h6" component="h3" sx={{ fontWeight: 600 }}>
              Related Clauses
            </Typography>
          </Box>
          
          <List disablePadding>
            {results.relatedClauses.map((clause, index) => (
              <React.Fragment key={`clause-${index}`}>
                <ListItem 
                  disableGutters 
                  sx={{ 
                    py: 2, 
                    px: 0,
                    flexDirection: 'column',
                    alignItems: 'flex-start',
                    '&:not(:last-child)': {
                      borderBottom: '1px solid',
                      borderColor: 'divider',
                      pb: 2,
                      mb: 2
                    }
                  }}
                >
                  <Box sx={{ width: '100%', display: 'flex', justifyContent: 'space-between', mb: 1 }}>
                    <Chip 
                      label={clause.section} 
                      size="small" 
                      color="primary" 
                      variant="outlined"
                      sx={{ fontWeight: 500, mb: 1 }}
                    />
                    <Box>
                      <Tooltip title="Copy text">
                        <IconButton 
                          size="small" 
                          onClick={() => handleCopyToClipboard(clause.text)}
                          sx={{ ml: 1 }}
                        >
                          <ContentCopyIcon fontSize="small" />
                        </IconButton>
                      </Tooltip>
                      {policySource?.type === 'url' && (
                        <Tooltip title="View in original document">
                          <IconButton 
                            size="small" 
                            onClick={() => window.open(`${policySource.url}#${clause.section.toLowerCase().replace(/\s+/g, '-')}`, '_blank')}
                            sx={{ ml: 1 }}
                          >
                            <OpenInNewIcon fontSize="small" />
                          </IconButton>
                        </Tooltip>
                      )}
                    </Box>
                  </Box>
                  <Typography variant="body1" color="text.primary" sx={{ mb: 1 }}>
                    {clause.text}
                  </Typography>
                  <Box sx={{ display: 'flex', alignItems: 'center', mt: 1 }}>
                    <Box sx={{ 
                      width: 60, 
                      height: 4, 
                      bgcolor: 'divider', 
                      borderRadius: 2, 
                      overflow: 'hidden',
                      mr: 1
                    }}>
                      <Box 
                        sx={{ 
                          height: '100%', 
                          bgcolor: clause.relevance > 0.7 ? 'success.main' : 'warning.main',
                          width: `${clause.relevance * 100}%`
                        }} 
                      />
                    </Box>
                    <Typography variant="caption" color="text.secondary">
                      {Math.round(clause.relevance * 100)}% relevant
                    </Typography>
                  </Box>
                </ListItem>
              </React.Fragment>
            ))}
          </List>
        </Paper>
      )}

      {/* PDF Viewer */}
      {pdfUrl && policySource?.type === 'file' && (
        <Paper 
          elevation={0} 
          sx={{ 
            mt: 4, 
            p: 4, 
            borderRadius: 3,
            border: '1px solid',
            borderColor: 'divider',
            bgcolor: 'background.paper'
          }}
        >
          <Box sx={{ display: 'flex', alignItems: 'center', mb: 3 }}>
            <ArticleIcon color="primary" sx={{ mr: 1.5, fontSize: 28 }} />
            <Typography variant="h6" component="h3" sx={{ fontWeight: 600 }}>
              Document Viewer
            </Typography>
          </Box>
          <Box 
            sx={{ 
              border: '1px solid', 
              borderColor: 'divider', 
              borderRadius: 2,
              overflow: 'hidden',
              maxHeight: '70vh',
              overflowY: 'auto'
            }}
          >
            <Document
              file={pdfUrl}
              onLoadSuccess={onDocumentLoadSuccess}
              loading={
                <Box sx={{ p: 4, textAlign: 'center' }}>
                  <CircularProgress />
                  <Typography variant="body2" sx={{ mt: 2 }}>Loading document...</Typography>
                </Box>
              }
            >
              {Array.from(new Array(numPages), (el, index) => (
                <Page 
                  key={`page_${index + 1}`} 
                  pageNumber={index + 1} 
                  width={Math.min(800, window.innerWidth - 64)}
                  renderTextLayer={true}
                  renderAnnotationLayer={true}
                  loading={
                    <Box sx={{ p: 4, textAlign: 'center' }}>
                      <CircularProgress size={24} />
                      <Typography variant="body2" sx={{ mt: 1 }}>Loading page {index + 1}...</Typography>
                    </Box>
                  }
                />
              ))}
            </Document>
          </Box>
          {numPages > 1 && (
            <Box sx={{ mt: 2, display: 'flex', justifyContent: 'center', alignItems: 'center' }}>
              <IconButton 
                onClick={() => setPageNumber(p => Math.max(1, p - 1))} 
                disabled={pageNumber <= 1}
              >
                <ExpandMoreIcon sx={{ transform: 'rotate(90deg)' }} />
              </IconButton>
              <Typography variant="body2" sx={{ mx: 2 }}>
                Page {pageNumber} of {numPages}
              </Typography>
              <IconButton 
                onClick={() => setPageNumber(p => Math.min(numPages, p + 1))} 
                disabled={pageNumber >= numPages}
              >
                <ExpandMoreIcon sx={{ transform: 'rotate(-90deg)' }} />
              </IconButton>
            </Box>
          )}
        </Paper>
      )}
      
      {/* PDF Viewer Container (hidden by default) */}
      <div ref={pdfViewerRef} className="pdf-viewer" style={{ display: 'none' }}>
        {/* PDF viewer will be rendered here */}
      </div>
      
      <style jsx>{`
        .analysis-results {
          margin-top: 2rem;
          background: white;
          border-radius: var(--border-radius);
          padding: 1.5rem;
          box-shadow: var(--box-shadow);
        }
        
        h2 {
          color: var(--primary-color);
          margin-bottom: 1.5rem;
          font-size: 1.75rem;
        }
        
        h3 {
          color: var(--secondary-color);
          margin: 1.5rem 0 1rem;
          font-size: 1.25rem;
        }
        
        .result-section {
          margin-bottom: 2rem;
        }
        
        .result-content {
          background: #f8f9fa;
          padding: 1.25rem;
          border-radius: var(--border-radius);
          line-height: 1.6;
        }
        
        .key-points, .concerns-list {
          list-style: none;
          padding: 0;
          margin: 0;
        }
        
        .key-point, .concern-item {
          padding: 0.75rem 0;
          border-bottom: 1px solid #eee;
          display: flex;
          flex-direction: column;
          align-items: flex-start;
        }
        
        .related-clauses {
          margin-top: 0.5rem;
          font-size: 0.9em;
          color: #555;
          width: 100%;
        }
        
        .clauses-label {
          display: block;
          font-weight: 500;
          margin-bottom: 0.25rem;
        }
        
        .clauses-list {
          list-style: none;
          padding: 0;
          margin: 0.25rem 0 0;
          display: flex;
          flex-wrap: wrap;
          gap: 0.5rem;
        }
        
        .clause-item {
          display: inline-block;
        }
        
        .clause-link {
          color: var(--primary-color);
          text-decoration: none;
          padding: 0.25rem 0.5rem;
          border-radius: 4px;
          background-color: rgba(74, 111, 165, 0.1);
          transition: background-color 0.2s ease;
          white-space: nowrap;
        }
        
        .clause-link:hover {
          background-color: rgba(74, 111, 165, 0.2);
          text-decoration: underline;
        }
        
        .key-point:last-child, .concern-item:last-child {
          border-bottom: none;
        }
        
        .point-text, .concern-text {
          flex: 1;
        }
        
        .concerns {
          background-color: #fff5f5;
          padding: 1rem;
          border-radius: var(--border-radius);
          border-left: 4px solid #e53e3e;
        }
        
        .loading-container {
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;
          padding: 3rem 1rem;
          text-align: center;
        }
        
        .spinner {
          width: 40px;
          height: 40px;
          border: 4px solid rgba(0, 0, 0, 0.1);
          border-radius: 50%;
          border-top-color: var(--primary-color);
          animation: spin 1s ease-in-out infinite;
          margin-bottom: 1rem;
        }
        
        @keyframes spin {
          to { transform: rotate(360deg); }
        }
        
        .error-container {
          background-color: #fff5f5;
          border: 1px solid #fc8181;
          border-radius: var(--border-radius);
          padding: 1rem;
          margin: 1rem 0;
          color: #e53e3e;
        }
        
        /* Mobile styles */
        @media (max-width: 768px) {
          .analysis-results {
            padding: 1rem;
            margin: 1rem -1rem 0;
            border-radius: 0;
            box-shadow: none;
          }
          
          h2 {
            font-size: 1.5rem;
          }
          
          h3 {
            font-size: 1.1rem;
          }
          
          .result-content {
            padding: 1rem;
          }
        }
      `}</style>
    </Box>
  );
};

export default AnalysisResults;
